import React, { useState, useEffect } from 'react';
import './App.css';
import { 
  Container, 
  Typography, 
  Box, 
  Button, 
  Paper,
  Grid,
  IconButton,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  TextField,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Stack
} from '@mui/material';
import { 
  Add as AddIcon, 
  Delete as DeleteIcon,
  CalendarMonth as CalendarIcon,
  ViewList as ListIcon,
  ViewModule as GridIcon
} from '@mui/icons-material';
import { AdapterDateFns } from '@mui/x-date-pickers/AdapterDateFns';
import { LocalizationProvider, DatePicker, DateTimePicker } from '@mui/x-date-pickers';
import { format, isSameMonth, addMonths, subMonths } from 'date-fns';

function App() {
  const [events, setEvents] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [currentDate, setCurrentDate] = useState(new Date());
  const [viewType, setViewType] = useState('month');
  const [formData, setFormData] = useState({
    studentId: '',
    eventType: '',
    date: new Date(),
    description: ''
  });

  const eventTypes = {
    'class': { name: 'Class', color: '#4CAF50' },
    'study': { name: 'Study', color: '#2196F3' },
    'exercise': { name: 'Exercise', color: '#FF9800' },
    'other': { name: 'Other', color: '#9C27B0' }
  };

  useEffect(() => {
    const savedEvents = localStorage.getItem('events');
    if (savedEvents) {
      setEvents(JSON.parse(savedEvents));
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('events', JSON.stringify(events));
  }, [events]);

  const handleAddEvent = () => {
    if (!formData.studentId || !formData.eventType) {
      alert('Please fill in all required fields');
      return;
    }

    const newEvent = {
      id: Date.now(),
      ...formData,
      date: formData.date.toISOString()
    };

    setEvents([...events, newEvent]);
    setShowForm(false);
    setFormData({
      studentId: '',
      eventType: '',
      date: new Date(),
      description: ''
    });
  };

  const handleDeleteEvent = (eventId) => {
    setEvents(events.filter(event => event.id !== eventId));
  };

  const handleDateChange = (date) => {
    setCurrentDate(date);
  };

  const handleViewChange = (type) => {
    setViewType(type);
  };

  const filteredEvents = events.filter(event => {
    const eventDate = new Date(event.date);
    if (viewType === 'month') {
      return isSameMonth(eventDate, currentDate);
    }
    return true;
  });

  const renderEvents = () => {
    if (viewType === 'list') {
      return (
        <Box sx={{ mt: 2 }}>
          {filteredEvents.map(event => (
            <Paper key={event.id} sx={{ p: 2, mb: 2 }}>
              <Grid container alignItems="center" spacing={2}>
                <Grid item xs>
                  <Typography variant="h6">{eventTypes[event.eventType].name}</Typography>
                  <Typography variant="body2">Student ID: {event.studentId}</Typography>
                  <Typography variant="body2">
                    {format(new Date(event.date), 'PPpp')}
                  </Typography>
                  {event.description && (
                    <Typography variant="body2">{event.description}</Typography>
                  )}
                </Grid>
                <Grid item>
                  <IconButton 
                    onClick={() => handleDeleteEvent(event.id)}
                    color="error"
                  >
                    <DeleteIcon />
                  </IconButton>
                </Grid>
              </Grid>
            </Paper>
          ))}
        </Box>
      );
    }

    return (
      <Box sx={{ mt: 2 }}>
        <Grid container spacing={2}>
          {filteredEvents.map(event => (
            <Grid item xs={12} sm={6} md={4} key={event.id}>
              <Paper 
                sx={{ 
                  p: 2,
                  borderLeft: `4px solid ${eventTypes[event.eventType].color}`
                }}
              >
                <Typography variant="h6">{eventTypes[event.eventType].name}</Typography>
                <Typography variant="body2">Student ID: {event.studentId}</Typography>
                <Typography variant="body2">
                  {format(new Date(event.date), 'PPpp')}
                </Typography>
                {event.description && (
                  <Typography variant="body2">{event.description}</Typography>
                )}
                <IconButton 
                  onClick={() => handleDeleteEvent(event.id)}
                  color="error"
                  size="small"
                  sx={{ mt: 1 }}
                >
                  <DeleteIcon />
                </IconButton>
              </Paper>
            </Grid>
          ))}
        </Grid>
      </Box>
    );
  };

  return (
    <Container maxWidth="lg">
      <Box sx={{ my: 4 }}>
        <Box sx={{ display: 'flex', alignItems: 'center', mb: 4 }}>
          <Box sx={{ flexGrow: 1 }}>
            <Typography variant="h4" component="h1" gutterBottom>
              P.A.S.E Daily Tracker
            </Typography>
            <Typography variant="subtitle1" color="text.secondary">
              Track your daily activities and progress
            </Typography>
          </Box>
          <Box sx={{ display: 'flex', gap: 2 }}>
            <Button
              variant="contained"
              startIcon={<AddIcon />}
              onClick={() => setShowForm(true)}
            >
              Add Event
            </Button>
          </Box>
        </Box>

        <Paper sx={{ p: 2, mb: 3 }}>
          <Grid container spacing={2} alignItems="center">
            <Grid item xs={12} md={4}>
              <LocalizationProvider dateAdapter={AdapterDateFns}>
                <DatePicker
                  label="Select Date"
                  value={currentDate}
                  onChange={handleDateChange}
                  renderInput={(params) => <TextField {...params} fullWidth />}
                />
              </LocalizationProvider>
            </Grid>
            <Grid item xs={12} md={8}>
              <Box sx={{ display: 'flex', gap: 2, justifyContent: 'flex-end' }}>
                <Button
                  variant={viewType === 'month' ? 'contained' : 'outlined'}
                  startIcon={<CalendarIcon />}
                  onClick={() => handleViewChange('month')}
                >
                  Month
                </Button>
                <Button
                  variant={viewType === 'list' ? 'contained' : 'outlined'}
                  startIcon={<ListIcon />}
                  onClick={() => handleViewChange('list')}
                >
                  List
                </Button>
                <Button
                  variant={viewType === 'grid' ? 'contained' : 'outlined'}
                  startIcon={<GridIcon />}
                  onClick={() => handleViewChange('grid')}
                >
                  Grid
                </Button>
              </Box>
            </Grid>
          </Grid>
        </Paper>

        {renderEvents()}

        <Dialog open={showForm} onClose={() => setShowForm(false)} maxWidth="sm" fullWidth>
          <DialogTitle>Add New Event</DialogTitle>
          <DialogContent>
            <Stack spacing={3} sx={{ mt: 2 }}>
              <TextField
                label="Student ID"
                value={formData.studentId}
                onChange={(e) => setFormData({ ...formData, studentId: e.target.value })}
                fullWidth
                required
              />
              <FormControl fullWidth required>
                <InputLabel>Event Type</InputLabel>
                <Select
                  value={formData.eventType}
                  label="Event Type"
                  onChange={(e) => setFormData({ ...formData, eventType: e.target.value })}
                >
                  {Object.entries(eventTypes).map(([key, value]) => (
                    <MenuItem key={key} value={key}>
                      {value.name}
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>
              <LocalizationProvider dateAdapter={AdapterDateFns}>
                <DateTimePicker
                  label="Date & Time"
                  value={formData.date}
                  onChange={(newValue) => setFormData({ ...formData, date: newValue })}
                  renderInput={(params) => <TextField {...params} fullWidth />}
                />
              </LocalizationProvider>
              <TextField
                label="Description"
                value={formData.description}
                onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                fullWidth
                multiline
                rows={4}
              />
            </Stack>
          </DialogContent>
          <DialogActions>
            <Button onClick={() => setShowForm(false)}>Cancel</Button>
            <Button onClick={handleAddEvent} variant="contained">
              Add Event
            </Button>
          </DialogActions>
        </Dialog>
      </Box>
    </Container>
  );
}

export default App; 